import { useEffect, useState } from "react";
import toast from "react-hot-toast";
import { useAppStore } from "../store/appStore";
import ValidateTab from "../components/tabs/ValidateTab";
import BulkUploadTab from "../components/tabs/BulkUploadTab";
import HistoryTab from "../components/tabs/HistoryTab";

const TABS = ["validate", "bulk", "history"];

export default function DashboardPage() {
  const { user, subscription, fetchSubscription, online } = useAppStore();
  const [tab, setTab] = useState("validate");

  useEffect(() => {
    fetchSubscription().catch(() => {
      toast.error("Failed to load subscription");
    });
  }, [fetchSubscription]);

  return (
    <div className="space-y-4">
      <div className="card flex flex-wrap items-center justify-between gap-4">
        <div>
          <h2 className="text-xl font-semibold">Welcome, {user?.firstName || user?.email}</h2>
          <p className="text-sm text-slate-600">
            Credits: <strong>{subscription?.currentCredits ?? "-"}</strong> / {subscription?.creditsPerMonth ?? "-"}
          </p>
        </div>
        <div className="flex items-center gap-3">
          <span className={`rounded-full px-3 py-1 text-xs font-semibold ${online ? "bg-emerald-100 text-emerald-700" : "bg-amber-100 text-amber-700"}`}>
            {online ? "Online" : "Offline mode"}
          </span>
        </div>
      </div>

      <div className="flex gap-2">
        {TABS.map((item) => (
          <button key={item} className={`btn capitalize ${tab === item ? "btn-primary" : "btn-outline"}`} onClick={() => setTab(item)}>
            {item === "bulk" ? "Bulk Upload" : item}
          </button>
        ))}
      </div>

      {tab === "validate" && <ValidateTab />}
      {tab === "bulk" && <BulkUploadTab />}
      {tab === "history" && <HistoryTab />}
    </div>
  );
}
